  ('judicial-d35ec6db-moex-00345', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '依行政程序法之規定，關於公法上請求權之時效，下列敘述何者正確？', '["債務人因時效完成而發生抗辯權", "因行政處分而中斷之時效，自行政處分送達相對人或使其知悉時，重行起算", "行政處分如因撤銷而溯及既往失效時，自該處分失效時起，已中斷之時效視為不中斷", "行政處分如因廢止而溯及既往失效時，自該處分失效時起，重行起算時效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
